object ConfigXmlParser {

  private def createSecureSAXParser(): javax.xml.parsers.SAXParser = {
    val factory = SAXParserFactory.newInstance()
    // Disable external entities to prevent XXE attacks
    factory.setFeature("http://apache.org/xml/features/disallow-doctype-decl", false)
    factory.setFeature("http://xml.org/sax/features/external-general-entities", false)
    factory.setFeature("http://xml.org/sax/features/external-parameter-entities", false)
    factory.setFeature("http://apache.org/xml/features/nonvalidating/load-external-dtd", false)
    factory.setXIncludeAware(false)
    factory.setNamespaceAware(false)
    factory.newSAXParser()
  }

  def parseXmlConfig(xmlString: String): ParseResult = {
    Try {
      val parser = createSecureSAXParser()
      val xmlNode = XML.withSAXParser(parser).loadString(xmlString)
      extractSettings(xmlNode)
    } match {
      case Success(settings) =>
        ParseResult(success = true, settings = settings, errors = List.empty)
      case Failure(ex) =>
        ParseResult(success = false, settings = List.empty, errors = List(s"XML parsing error: ${ex.getMessage}"))
    }
  }

  private def extractSettings(root: Node): List[ConfigSetting] = {
    val topLevelSettings = extractDirectSettings(root, section = None)
    val sectionSettings = (root \ "section").flatMap { sectionNode =>
      val sectionName = (sectionNode \ "@name").text
      extractDirectSettings(sectionNode, Some(sectionName))
    }
    val propertyGroupSettings = (root \ "propertyGroup").flatMap { groupNode =>
      val groupName = (groupNode \ "@name").text
      extractDirectSettings(groupNode, Some(groupName))
    }
    val environmentSettings = (root \ "environment").flatMap { envNode =>
      val envName = (envNode \ "@name").text
      extractDirectSettings(envNode, Some(s"environment:$envName"))
    }
    val nestedSectionSettings = (root \\ "section").flatMap { sectionNode =>
      val sectionName = (sectionNode \ "@name").text
      if (sectionNode.parent != null && sectionNode.parent != root) {
        extractDirectSettings(sectionNode, Some(sectionName))
      } else {
        Seq.empty
      }
    }

    (topLevelSettings ++ sectionSettings ++ propertyGroupSettings ++ environmentSettings ++ nestedSectionSettings).toList.distinct
  }

  private def extractDirectSettings(node: Node, section: Option[String]): Seq[ConfigSetting] = {
    val settingNodes = (node \ "setting").map { settingNode =>
      val key = (settingNode \ "@key").text match {
        case "" => (settingNode \ "@name").text
        case k => k
      }
      val value = (settingNode \ "@value").text match {
        case "" => settingNode.text.trim
        case v => v
      }
      ConfigSetting(key, value, section)
    }

    val propertyNodes = (node \ "property").map { propNode =>
      val key = (propNode \ "@name").text match {
        case "" => (propNode \ "@key").text
        case k => k
      }
      val value = (propNode \ "@value").text match {
        case "" => propNode.text.trim
        case v => v
      }
      ConfigSetting(key, value, section)
    }

    val entryNodes = (node \ "entry").map { entryNode =>
      val key = (entryNode \ "@key").text
      val value = entryNode.text.trim
      ConfigSetting(key, value, section)
    }

    (settingNodes ++ propertyNodes ++ entryNodes).filter(s => s.key.nonEmpty)
  }

  def resolveEntityReferences(settings: List[ConfigSetting]): List[ConfigSetting] = {
    val settingsMap = settings.map(s => s.key -> s.value).toMap

    val entityRefPattern = """\$\{([^}]+)\}""".r

    def resolveValue(value: String, depth: Int = 0): String = {
      if (depth > 10) value // prevent infinite recursion
      else {
        entityRefPattern.replaceAllIn(value, m => {
          val refKey = m.group(1)
          settingsMap.get(refKey) match {
            case Some(refValue) =>
              java.util.regex.Matcher.quoteReplacement(resolveValue(refValue, depth + 1))
            case None =>
              java.util.regex.Matcher.quoteReplacement(m.matched)
          }
        })
      }
    }

    settings.map(s => s.copy(value = resolveValue(s.value)))
  }
}

object ConfigManagementService extends App {

  import JsonProtocol._

  implicit val system: ActorSystem = ActorSystem("config-management")
  import system.dispatcher

  val route: Route =
    pathPrefix("api" / "config") {
      concat(
        path("parse") {
          post {
            entity(as[XmlRequest]) { request =>
              val result = ConfigXmlParser.parseXmlConfig(request.xml)
              complete(StatusCodes.OK -> result)
            }
          }
