            entity(as[XmlRequest]) { request =>
              val parseResult = ConfigXmlParser.parseXmlConfig(request.xml)
              if (parseResult.success) {
                val resolvedSettings = ConfigXmlParser.resolveEntityReferences(parseResult.settings)
                complete(StatusCodes.OK -> parseResult.copy(settings = resolvedSettings))
              } else {
                complete(StatusCodes.BadRequest -> parseResult)
              }
            }
          }
        },
        path("validate") {
          post {
            entity(as[XmlRequest]) { request =>
              val result = ConfigXmlParser.parseXmlConfig(request.xml)
              val response = JsObject(
                "valid" -> JsBoolean(result.success),
                "settingsCount" -> JsNumber(result.settings.size),
                "errors" -> result.errors.toJson
              )
              if (result.success) {
                complete(StatusCodes.OK -> response)
              } else {
                complete(StatusCodes.BadRequest -> response)
              }
            }
          }
        },
        path("extract" / Segment) { sectionName =>
          post {
            entity(as[XmlRequest]) { request =>
              val result = ConfigXmlParser.parseXmlConfig(request.xml)
              if (result.success) {
                val sectionSettings = result.settings.filter(_.section.contains(sectionName))
                val resolved = ConfigXmlParser.resolveEntityReferences(sectionSettings)
                complete(StatusCodes.OK -> ParseResult(success = true, settings = resolved, errors = List.empty))
              } else {
                complete(StatusCodes.BadRequest -> result)
              }
            }
          }
        },
        path("health") {
          get {
            complete(StatusCodes.OK -> JsObject("status" -> JsString("healthy")))
          }
